use std::collections::VecDeque;

fn solve(edges: Vec<Vec<i64>>, online: Vec<bool>, k: i64) -> i64 {
    let n = online.len();
    if n == 0 {
        return -1;
    }

    // Build adjacency list for topological sort
    let mut adj = vec![vec![]; n];
    for edge in &edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        adj[u].push(v);
    }

    let mut in_degree = vec![0; n];
    for edge in &edges {
        let v = edge[1] as usize;
        in_degree[v] += 1;
    }

    let mut queue = VecDeque::new();
    for i in 0..n {
        if in_degree[i] == 0 {
            queue.push_back(i);
        }
    }

    let mut topological_order = Vec::new();
    while let Some(node) = queue.pop_front() {
        topological_order.push(node);
        for &v in &adj[node] {
            in_degree[v] -= 1;
            if in_degree[v] == 0 {
                queue.push_back(v);
            }
        }
    }

    // Find max cost
    let mut max_cost = 0;
    for edge in &edges {
        let cost = edge[2];
        if cost > max_cost {
            max_cost = cost;
        }
    }

    let is_possible = |mid: i64| {
        let mut filtered_adj = vec![vec![]; n];
        for edge in &edges {
            let u = edge[0] as usize;
            let v = edge[1] as usize;
            let cost = edge[2];
            if cost >= mid && online[u] && online[v] {
                filtered_adj[u].push((v, cost));
            }
        }

        let mut dp = vec![i64::MAX; n];
        dp[0] = 0;

        for &node in &topological_order {
            if !online[node] {
                continue;
            }
            if dp[node] == i64::MAX {
                continue;
            }
            for (v, cost) in &filtered_adj[node] {
                if dp[node] + cost < dp[*v] {
                    dp[*v] = dp[node] + cost;
                }
            }
        }

        dp[n - 1] <= k
    };

    let mut low = 0;
    let mut high = max_cost;
    let mut answer = -1;

    while low <= high {
        let mid = (low + high) / 2;
        if is_possible(mid) {
            answer = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    answer
}
