function solve(edges, online, k) {
    const n = online.length;
    const originalAdj = new Map();
    for (const [u, v, cost] of edges) {
        if (!originalAdj.has(u)) originalAdj.set(u, []);
        originalAdj.get(u).push(v);
    }

    const inDegree = new Array(n).fill(0);
    for (const [u, v, cost] of edges) {
        inDegree[v]++;
    }

    const queue = [];
    for (let i = 0; i < n; i++) {
        if (inDegree[i] === 0) {
            queue.push(i);
        }
    }

    const topologicalOrder = [];
    while (queue.length > 0) {
        const u = queue.shift();
        topologicalOrder.push(u);
        for (const v of originalAdj.get(u) || []) {
            inDegree[v]--;
            if (inDegree[v] === 0) {
                queue.push(v);
            }
        }
    }

    const maxCost = edges.reduce((max, [u, v, c]) => Math.max(max, c), 0);
    let low = 0;
    let high = maxCost;
    let answer = -1;

    function isPossible(x) {
        const adj = new Map();
        for (const [u, v, cost] of edges) {
            if (cost >= x && online[u] && online[v]) {
                if (!adj.has(u)) adj.set(u, []);
                adj.get(u).push({ v, cost });
            }
        }

        const dp = new Array(n).fill(Infinity);
        dp[0] = 0;

        for (const node of topologicalOrder) {
            if (!online[node]) continue;
            if (dp[node] === Infinity) continue;
            if (adj.has(node)) {
                for (const { v, cost } of adj.get(node)) {
                    if (dp[node] + cost < dp[v]) {
                        dp[v] = dp[node] + cost;
                    }
                }
            }
        }

        return dp[n - 1] <= k;
    }

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        if (isPossible(mid)) {
            answer = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return answer;
}
