```rust
fn solve(edges: Vec<Vec<i64>>, online: Vec<bool>, k: i64) -> i64 {
    let n = online.len();
    let mut adj_topo = vec![vec![]; n];
    let mut in_degree = vec![0; n];
    for edge in &edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        adj_topo[u].push(v);
        in_degree[v] += 1;
    }
    let mut queue = Vec::new();
    for i in 0..n {
        if in_degree[i] == 0 {
            queue.push(i as i32);
        }
    }
    let mut topological_order = Vec::new();
    while let Some(node) = queue.pop() {
        topological_order.push(node);
        for &v in &adj_topo[node as usize] {
            let v_idx = v as usize;
            in_degree[v_idx] -= 1;
            if in_degree[v_idx] == 0 {
                queue.push(v);
            }
        }
    }
    let max_cost = edges.iter().map(|e| e[2]).max().unwrap_or(0);
    let mut low = 0;
    let mut high = max_cost;
    let mut answer = -1;
    while low <= high {
        let mid = (low + high) / 2;
        let mut adj = vec![vec![]; n];
        for edge in &edges {
            let u = edge[0] as usize;
            let v = edge[1] as usize;
            let cost = edge[2];
            if cost >= mid && online[u] && online[v] {
                adj[u].push((v, cost));
            }
        }
        let mut dp = vec![i64::MAX; n];
        dp[0] = 0;
        for &node in &topological_order {
            let node = node as usize;
            if !online[node] {
                continue;
            }
            if dp[node] == i64::MAX {
                continue;
            }
            for (v, cost) in &adj[node] {
                let new_cost = dp[node] + *cost;
                if new_cost < dp[*v] {
                    dp[*v] = new_cost;
                }
            }
        }
        if dp[n - 1] <= k {
            answer = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }
    answer
}
