use std::collections::VecDeque;

fn solve(edges: Vec<Vec<i64>>, online: Vec<bool>, k: i64) -> i64 {
    let n = online.len();
    let mut original_adj = vec![vec![]; n];
    let mut in_degree = vec![0; n];
    for edge in &edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        original_adj[u].push(v);
        in_degree[v] += 1;
    }

    let mut queue = VecDeque::new();
    for i in 0..n {
        if in_degree[i] == 0 {
            queue.push_back(i);
        }
    }

    let mut topological_order = vec![];
    while let Some(node) = queue.pop_front() {
        topological_order.push(node);
        for &neighbor in &original_adj[node] {
            in_degree[neighbor] -= 1;
            if in_degree[neighbor] == 0 {
                queue.push_back(neighbor);
            }
        }
    }

    let mut max_cost = 0;
    for edge in &edges {
        let cost = edge[2];
        if cost > max_cost {
            max_cost = cost;
        }
    }

    let mut low = 0;
    let mut high = max_cost;
    let mut answer = -1;

    while low <= high {
        let mid = (low + high) / 2;
        if is_possible(&edges, &online, &topological_order, mid, k, n) {
            answer = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

