fn solve(edges: Vec<Vec<i64>>, online: Vec<bool>, k: i64) -> i64 {
    let n = online.len();
    if n == 0 {
        return -1;
    }

    // Step 1: Topological sort
    let mut adj = vec![vec![]; n];
    let mut in_degree = vec![0; n];
    for edge in &edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        adj[u].push(v);
        in_degree[v] += 1;
    }

    let mut queue = Vec::new();
    for i in 0..n {
        if in_degree[i] == 0 {
            queue.push(i);
        }
    }

    let mut top_order = Vec::new();
    while let Some(u) = queue.pop() {
        top_order.push(u);
        for &v in &adj[u] {
            in_degree[v] -= 1;
            if in_degree[v] == 0 {
                queue.push(v);
            }
        }
    }

    // Step 2: Binary search
    let mut low = 0;
    let mut high = edges.iter().map(|e| e[2]).max().unwrap_or(0);
    let mut answer = -1;

    while low <= high {
        let mid = (low + high) / 2;
        let mut adj_mid = vec![vec![]; n];
        for edge in &edges {
            let u = edge[0] as usize;
            let v = edge[1] as usize;
            let cost = edge[2];
            if cost >= mid && online[u] && online[v] {
                adj_mid[u].push((v, cost));
            }
        }

        let mut dp = vec![i64::MAX; n];
        dp[0] = 0;

        for &node in &top_order {
            if !online[node] {
                continue;
            }
            if dp[node] == i64::MAX {
                continue;
            }
            for (v, cost) in &adj_mid[node] {
                if dp[*v] > dp[node] + cost {
                    dp[*v] = dp[node] + cost;
                }
            }
        }

        if dp[n - 1] <= k {
            answer = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    answer
}
